import React from 'react';
import { ArrowRight } from 'lucide-react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary';
  fullWidth?: boolean;
  subtext?: string;
  onClick?: () => void;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  subtext,
  className = '',
  ...props 
}) => {
  const baseStyles = "relative font-bold py-4 px-6 rounded-xl transition-all duration-200 transform active:scale-95 shadow-lg flex flex-col items-center justify-center text-center";
  const variants = {
    primary: "bg-orange-500 hover:bg-orange-600 text-white shadow-orange-500/30",
    secondary: "bg-white text-orange-600 border-2 border-orange-100 hover:bg-orange-50"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      <span className="flex items-center justify-center gap-2 text-lg uppercase tracking-wide">
        {children}
        <ArrowRight className="w-5 h-5" />
      </span>
      {subtext && (
        <span className="text-xs font-normal opacity-90 mt-1 block">
          {subtext}
        </span>
      )}
    </button>
  );
};

